#include <cctype>
#include <fstream>
#include <iostream>
#include <sstream>
#include <string>
#include <unordered_map>

namespace {

struct Location
{
  std::string file;
  int line = 1;
  int col = 1;
};

struct Token
{
  std::string kind;
  std::string text;
  Location loc;
  bool startOfLine = false;
  bool leadingSpace = false;
};

bool
isIdentStart(char c)
{
  return std::isalpha(static_cast<unsigned char>(c)) || c == '_';
}

bool
isIdentContinue(char c)
{
  return std::isalnum(static_cast<unsigned char>(c)) || c == '_';
}

bool
isHexDigit(char c)
{
  return std::isxdigit(static_cast<unsigned char>(c));
}

void
printToken(std::ofstream& out, const Token& token)
{
  out << token.kind << " '" << token.text << "'\t";
  if (token.startOfLine)
    out << " [StartOfLine]";
  if (token.leadingSpace)
    out << " [LeadingSpace]";
  out << "\tLoc=<" << token.loc.file << ':' << token.loc.line << ':'
      << token.loc.col << ">\n";
}

class Scanner
{
public:
  Scanner(std::string input, std::string fallbackFile)
    : mInput(std::move(input))
    , mCurrentFile(std::move(fallbackFile))
    , mLastTokenEnd{ mCurrentFile, 1, 1 }
  {
  }

  void run(std::ofstream& out)
  {
    while (mPos < mInput.size()) {
      if (mAtStartOfLine && mInput[mPos] == '#') {
        consumeLineMarker();
        continue;
      }

      const char c = mInput[mPos];
      if (consumeWhitespace(c) || consumeComment())
        continue;

      Token token;
      token.loc = { mCurrentFile, mLine, mCol };
      token.startOfLine = mAtStartOfLine;
      token.leadingSpace = mLeadingSpace;

      if (scanIdentifier(token) || scanNumber(token) || scanString(token) ||
          scanPunctuation(token)) {
        printToken(out, token);
        mLastTokenEnd = { token.loc.file,
                          token.loc.line,
                          token.loc.col + static_cast<int>(token.text.size()) };
        mAtStartOfLine = false;
        mLeadingSpace = false;
        continue;
      }

      advance();
    }

    out << "eof ''\t\tLoc=<" << mLastTokenEnd.file << ':'
        << mLastTokenEnd.line << ':' << mLastTokenEnd.col << ">\n";
  }

private:
  void advance()
  {
    ++mPos;
    ++mCol;
  }

  bool startsWith(const std::string& text) const
  {
    return mInput.compare(mPos, text.size(), text) == 0;
  }

  void consumeNewline()
  {
    if (mInput[mPos] == '\r') {
      ++mPos;
      if (mPos < mInput.size() && mInput[mPos] == '\n')
        ++mPos;
    } else {
      ++mPos;
    }
    ++mLine;
    mCol = 1;
    mAtStartOfLine = true;
    mLeadingSpace = false;
  }

  bool consumeWhitespace(char c)
  {
    if (c == '\n' || c == '\r') {
      consumeNewline();
      return true;
    }
    if (c == ' ' || c == '\t' || c == '\v' || c == '\f') {
      mLeadingSpace = true;
      advance();
      return true;
    }
    return false;
  }

  bool consumeComment()
  {
    if (startsWith("//")) {
      mLeadingSpace = true;
      while (mPos < mInput.size() && mInput[mPos] != '\n' &&
             mInput[mPos] != '\r')
        advance();
      return true;
    }
    if (startsWith("/*")) {
      mLeadingSpace = true;
      advance();
      advance();
      while (mPos < mInput.size()) {
        if (startsWith("*/")) {
          advance();
          advance();
          break;
        }
        if (mInput[mPos] == '\n' || mInput[mPos] == '\r')
          consumeNewline();
        else
          advance();
      }
      mLeadingSpace = true;
      return true;
    }
    return false;
  }

  void consumeLineMarker()
  {
    const auto begin = mPos;
    while (mPos < mInput.size() && mInput[mPos] != '\n' && mInput[mPos] != '\r')
      ++mPos;

    const std::string line = mInput.substr(begin, mPos - begin);
    std::size_t i = 1;
    while (i < line.size() && std::isspace(static_cast<unsigned char>(line[i])))
      ++i;
    if (line.compare(i, 4, "line") == 0 &&
        (i + 4 == line.size() ||
         std::isspace(static_cast<unsigned char>(line[i + 4])))) {
      i += 4;
      while (i < line.size() && std::isspace(static_cast<unsigned char>(line[i])))
        ++i;
    }

    int nextLine = 0;
    while (i < line.size() && std::isdigit(static_cast<unsigned char>(line[i]))) {
      nextLine = nextLine * 10 + (line[i] - '0');
      ++i;
    }
    while (i < line.size() && std::isspace(static_cast<unsigned char>(line[i])))
      ++i;
    if (i < line.size() && line[i] == '"') {
      ++i;
      std::string file;
      while (i < line.size() && line[i] != '"') {
        if (line[i] == '\\' && i + 1 < line.size()) {
          file += line[i + 1];
          i += 2;
        } else {
          file += line[i++];
        }
      }
      if (!file.empty())
        mCurrentFile = file;
    }
    if (nextLine > 0)
      mLine = nextLine;

    if (mPos < mInput.size()) {
      if (mInput[mPos] == '\r') {
        ++mPos;
        if (mPos < mInput.size() && mInput[mPos] == '\n')
          ++mPos;
      } else if (mInput[mPos] == '\n') {
        ++mPos;
      }
    }
    mCol = 1;
    mAtStartOfLine = true;
    mLeadingSpace = false;
  }

  bool scanIdentifier(Token& token)
  {
    if (!isIdentStart(mInput[mPos]))
      return false;

    const auto begin = mPos;
    advance();
    while (mPos < mInput.size() && isIdentContinue(mInput[mPos]))
      advance();
    token.text = mInput.substr(begin, mPos - begin);

    static const std::unordered_map<std::string, std::string> keywords = {
      { "int", "int" },       { "void", "void" },
      { "const", "const" },   { "return", "return" },
      { "if", "if" },         { "else", "else" },
      { "while", "while" },   { "break", "break" },
      { "continue", "continue" },
    };
    const auto it = keywords.find(token.text);
    token.kind = it == keywords.end() ? "identifier" : it->second;
    return true;
  }

  bool scanNumber(Token& token)
  {
    if (!std::isdigit(static_cast<unsigned char>(mInput[mPos])))
      return false;

    const auto begin = mPos;
    if (mInput[mPos] == '0' && mPos + 1 < mInput.size() &&
        (mInput[mPos + 1] == 'x' || mInput[mPos + 1] == 'X')) {
      advance();
      advance();
      while (mPos < mInput.size() && isHexDigit(mInput[mPos]))
        advance();
    } else {
      while (mPos < mInput.size() &&
             std::isdigit(static_cast<unsigned char>(mInput[mPos])))
        advance();
    }
    while (mPos < mInput.size() && isIdentContinue(mInput[mPos]))
      advance();

    token.kind = "numeric_constant";
    token.text = mInput.substr(begin, mPos - begin);
    return true;
  }

  bool scanString(Token& token)
  {
    const auto begin = mPos;
    if (mInput[mPos] == 'L' && mPos + 1 < mInput.size() && mInput[mPos + 1] == '"')
      advance();
    else if (mInput[mPos] != '"')
      return false;

    advance();
    while (mPos < mInput.size()) {
      if (mInput[mPos] == '\\') {
        advance();
        if (mPos < mInput.size())
          advance();
        continue;
      }
      if (mInput[mPos] == '"') {
        advance();
        break;
      }
      if (mInput[mPos] == '\n' || mInput[mPos] == '\r')
        break;
      advance();
    }
    token.kind = "string_literal";
    token.text = mInput.substr(begin, mPos - begin);
    return true;
  }

  bool scanPunctuation(Token& token)
  {
    static const std::unordered_map<std::string, std::string> twoChar = {
      { "==", "equalequal" },    { "!=", "exclaimequal" },
      { "<=", "lessequal" },     { ">=", "greaterequal" },
      { "&&", "ampamp" },        { "||", "pipepipe" },
      { "<<", "lessless" },      { ">>", "greatergreater" },
      { "++", "plusplus" },      { "--", "minusminus" },
    };
    if (mPos + 1 < mInput.size()) {
      const std::string text = mInput.substr(mPos, 2);
      const auto it = twoChar.find(text);
      if (it != twoChar.end()) {
        token.text = text;
        token.kind = it->second;
        advance();
        advance();
        return true;
      }
    }

    static const std::unordered_map<char, std::string> oneChar = {
      { '(', "l_paren" },   { ')', "r_paren" }, { '[', "l_square" },
      { ']', "r_square" },  { '{', "l_brace" }, { '}', "r_brace" },
      { '+', "plus" },      { '-', "minus" },   { '*', "star" },
      { '/', "slash" },     { '%', "percent" }, { '<', "less" },
      { '>', "greater" },   { '=', "equal" },   { '!', "exclaim" },
      { ';', "semi" },      { ',', "comma" },   { '&', "amp" },
      { '|', "pipe" },      { '^', "caret" },   { '~', "tilde" },
      { '?', "question" },  { ':', "colon" },   { '.', "period" },
    };
    const auto it = oneChar.find(mInput[mPos]);
    if (it == oneChar.end())
      return false;
    token.text.assign(1, mInput[mPos]);
    token.kind = it->second;
    advance();
    return true;
  }

  std::string mInput;
  std::size_t mPos = 0;
  std::string mCurrentFile;
  int mLine = 1;
  int mCol = 1;
  bool mAtStartOfLine = true;
  bool mLeadingSpace = false;
  Location mLastTokenEnd;
};

} // namespace

int
main(int argc, char* argv[])
{
  if (argc != 3) {
    std::cout << "Usage: " << argv[0] << " <input> <output>\n";
    return -1;
  }

  std::ifstream inFile(argv[1]);
  if (!inFile) {
    std::cout << "Error: unable to open input file: " << argv[1] << '\n';
    return -2;
  }

  std::ofstream outFile(argv[2]);
  if (!outFile) {
    std::cout << "Error: unable to open output file: " << argv[2] << '\n';
    return -3;
  }

  std::ostringstream buffer;
  buffer << inFile.rdbuf();
  Scanner(std::move(buffer).str(), argv[1]).run(outFile);
}
